  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `voters_election_id_user_id_unique`(`election_id` ASC, `user_id` ASC) USING BTREE,
  INDEX `voters_user_id_foreign`(`user_id` ASC) USING BTREE,
