  INDEX `voters_election_id_has_voted_index`(`election_id` ASC, `has_voted` ASC) USING BTREE,
  CONSTRAINT `voters_election_id_foreign` FOREIGN KEY (`election_id`) REFERENCES `elections` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT,
